<?php
 namespace WPAICG\Chat\Frontend\Ajax; use WPAICG\Utils\AIPKit_CORS_Manager; if (!defined('ABSPATH')) { exit; } function ajax_get_frontend_chat_nonce_logic(): void { $post_data = wp_unslash($_POST); AIPKit_CORS_Manager::handle_preflight_request(); $bot_id = 0; if (isset($post_data['bot_id'])) { $bot_id = absint($post_data['bot_id']); } if ($bot_id > 0) { $is_cross_origin = false; if (isset($_SERVER['HTTP_ORIGIN']) && !empty($_SERVER['HTTP_ORIGIN'])) { $origin = esc_url_raw(wp_unslash((string) $_SERVER['HTTP_ORIGIN'])); $site_url = get_site_url(); $site_parsed = wp_parse_url($site_url); $origin_parsed = wp_parse_url($origin); if ($origin_parsed && $site_parsed && ( ($origin_parsed['host'] ?? '') !== ($site_parsed['host'] ?? '') || ($origin_parsed['scheme'] ?? 'http') !== ($site_parsed['scheme'] ?? 'http') )) { $is_cross_origin = true; } } if ($is_cross_origin) { $origin_allowed = AIPKit_CORS_Manager::check_and_set_cors_headers($bot_id); if (!$origin_allowed) { wp_send_json_error([ 'message' => __('This domain is not permitted to access the chatbot.', 'gpt3-ai-content-generator'), 'code' => 'cors_denied' ], 403); return; } } } nocache_headers(); $nonce = wp_create_nonce('aipkit_frontend_chat_nonce'); wp_send_json_success(['nonce' => $nonce]); } 